arguments.argument:
if !gDeltaDoTicks { exit; }
if image_xscale=1
  x+=moveSpd
else
  x-=moveSpd

if type=0
{
  dirChange+=1
  if dirChange>=480
  {
    if image_xscale=1
      image_xscale=-1
    else
      image_xscale=1
    dirChange=irandom(300)
  }
}

if bSpotted=0
{
  if checkScreenArea(x,y,2)=1
  {
    global.recBirdsSeen+=1
    bSpotted=1
  }
}
